query:
SELECT COUNT(*) as total_expenses FROM expenses;
SELECT COUNT(DISTINCT parliamentarian_id) as parls_with_expenses FROM expenses;
SELECT p.name, p.party, p.state, COUNT(e.id) as expense_count, ROUND(SUM(CAST(e.amount AS DECIMAL(15,2))),2) as total_amount
FROM parliamentarians p
JOIN expenses e ON e.parliamentarian_id = p.id
WHERE p.source_camara = 1
GROUP BY p.id, p.name, p.party, p.state
ORDER BY total_amount DESC
LIMIT 10;

